function StudentRow({ student, onDelete }) {
  return (
    <tr>
      <td>{student.rollNumber}</td>
      <td>{student.name}</td>
      <td>{student.marks}</td>
      <td>
        <button className="delete-button" type="button" onClick={() => onDelete(student.rollNumber)}>
          Delete
        </button>
      </td>
    </tr>
  );
}

export default StudentRow;
